INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 0, 8, 100, 1, "", 40000, 0, 0, 36, "");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 0, 8, 150, 1, "ぺコリーヌ", 40001, 107501, 1, 37, "今日は記念日、お祝いですね！\n焼肉、お寿司、ピザ、ケーキ～☆\nあなたとパーティできるなんて、\n幸せです～♪");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 0, 8, 150, 2, "コッコロ", 40001, 107601, 1, 38, "この記念日を迎えられたのは、\n主さまの器量の賜物\nさすがは主さまでございます\nえらい、えらい♪");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 0, 8, 150, 3, "キャル", 40001, 107801, 1, 39, "あんたもけっこうやるじゃない！\nちょっとは…割と…け、けっこう\n見直しちゃったわ\n褒めてあげる♪");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 0, 8, 150, 4, "スズメ", 40001, 107701, 1, 40, "あなたと私にとって、\n今日は特別な日\nあなたの支えがあるから、\n私は頑張れるんです！");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 0, 8, 150, 5, "タマキ", 40001, 107901, 1, 41, "今日はキミにとっての\n特別な記念日だにゃ\nキミの活躍にはいつも\n猫ながら感謝してるにゃ～♪");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 0, 8, 150, 6, "ぺコリーヌ", 40001, 107501, 2, 42, "う～かき氷食べ過ぎて、\n身体が冷えちゃいました…\nあなたの体温で温めてください！\nギューーッ♪");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 0, 8, 150, 7, "コッコロ", 40001, 107601, 2, 43, "夏は危険がいっぱいと申します…\nですが、わたくしが主さまを\nしっかりとお守りいたしますよ");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 0, 8, 150, 8, "キャル", 40001, 107801, 2, 44, "ん～なんであんたと、ひと夏を\n過ごすことになったのかな…\n結構楽しいからいいけど！\nさ、まだまだ遊ぶわよ！");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 0, 8, 150, 9, "スズメ", 40001, 107701, 2, 45, "あなたと過ごすはじめての夏…\nいまからドキドキが止まりません\n楽しくて素敵な思い出が、\nまた一つ増えるんですね♪");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 0, 8, 150, 10, "タマキ", 40001, 107901, 2, 46, "夏は一番の稼ぎ時にゃのに、\n今年はキミと過ごしたいって\n思ってるにゃ楽しい思い出\n増やしてくれるかにゃ？");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (91002, 0, 8, 150, 1, "", 40003, 0, 0, 57, "");
