INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 0, 2, 1, 1, "リリ", 40011, 125801, 1, 321, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 0, 2, 1, 2, "クリア", 40011, 126001, 1, 322, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 0, 2, 1, 3, "プレシア", 40011, 126101, 1, 323, "んーと。\nこれ、あげる。\nはい");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 0, 2, 1, 4, "リリ", 40011, 125801, 2, 324, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 0, 2, 1, 5, "クリア", 40011, 126001, 2, 325, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです");
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 0, 2, 1, 6, "プレシア", 40011, 126101, 2, 326, "お兄。\nきてくれて、うれしい");
